const data = $input.first().json;
const list = data.list || [];
const date = data.date || '';
const note = data.note || '';
const dashUrl = data.dashboard_url || '';

if (list.length === 0) {
  const msg = note
    ? `📋 ${date}\n${note}`
    : `📋 ${date}\n本日の後確対象者はいません✅`;
  return [{ json: { message: msg, skip: true } }];
}

const lines = [
  `📋 本日の後確リスト`,
  `${date}（${list.length}件）`,
  `⬜ マッチング待ち → LINEで後追いしてください`,
  '',
];

list.forEach((c, i) => {
  const name = c.customer_name || c.hitomono_id;
  const kana = c.customer_kana ? `（${c.customer_kana}）` : '';
  lines.push(`${i + 1}. ${c.hitomono_id} ${name}${kana}`);
  lines.push(`   📅 インタビュー: ${c.interview_date} ${c.interview_time}`);
});

lines.push('');
lines.push(`▼ 電話後はこちらで結果入力`);
lines.push(dashUrl);

return [{ json: { message: lines.join('\n'), list, skip: false } }];
